 155→const classifyStatusBucket = (statusCode) => {
 156→    if (statusCode >= 200 && statusCode < 300) return '2xx';
 157→    if (statusCode >= 300 && statusCode < 400) return '3xx';
 158→    if (statusCode >= 400 && statusCode < 500) return '4xx';
 159→    if (statusCode >= 500 && statusCode < 600) return '5xx';
 160→    return 'other';
 161→};
