 167→const toPreviewText = (value, maxLength = SOCIAL_PREVIEW_MAX_CHARS) => {
 168→    const normalized = normalizeWhitespace(value);
 169→    if (!normalized) return '';
 170→    if (normalized.length <= maxLength) return normalized;
 171→    if (maxLength <= 3) return normalized.slice(0, maxLength);
 172→    return `${normalized.slice(0, maxLength - 3).trimEnd()}...`;
 173→};
