 183→const getRequestOrigin = (req) => {
 184→    const forwardedProto = String(req.headers['x-forwarded-proto'] || '').split(',')[0].trim().toLowerCase();
 185→    const forwardedHost = String(req.headers['x-forwarded-host'] || '').split(',')[0].trim();
 186→    const host = forwardedHost || req.get('host') || '';
 187→    const requestProtocol = String(req.protocol || '').trim().toLowerCase();
 188→    const protocol = forwardedProto === 'http' || forwardedProto === 'https'
 189→        ? forwardedProto
 190→        : requestProtocol === 'http' || requestProtocol === 'https'
 191→            ? requestProtocol
 192→            : 'https';
 193→
 194→    if (!host) {
 195→        return SITE_URL;
 196→    }
 197→
 198→    return `${protocol}://${host}`;
 199→};
