 307→const resolveAbsoluteHttpUrl = (rawUrl) => {
 308→    try {
 309→        const raw = String(rawUrl || '').trim();
 310→        if (!raw) return null;
 311→
 312→        const isSupabasePath =
 313→            raw.startsWith('/storage/v1/object/public/')
 314→            || raw.startsWith('storage/v1/object/public/');
 315→
 316→        const baseUrl = isSupabasePath && SUPABASE_URL
 317→            ? `${SUPABASE_URL}/`
 318→            : SITE_URL;
 319→
 320→        const parsed = new URL(raw, baseUrl);
 321→        if (parsed.protocol !== 'http:' && parsed.protocol !== 'https:') {
 322→            return null;
 323→        }
 324→        return parsed.toString();
 325→    } catch {
 326→        return null;
 327→    }
 328→};
