 330→const isPrivateIpv4Address = (ip) => {
 331→    const parts = ip.split('.').map((part) => Number(part));
 332→    if (parts.length !== 4 || parts.some((part) => !Number.isInteger(part) || part < 0 || part > 255)) {
 333→        return true;
 334→    }
 335→
 336→    const [a, b] = parts;
 337→    if (a === 10 || a === 127 || a === 0) return true;
 338→    if (a === 169 && b === 254) return true;
 339→    if (a === 172 && b >= 16 && b <= 31) return true;
 340→    if (a === 192 && b === 168) return true;
 341→    return false;
 342→};
 343→
 344→const isPrivateIpv6Address = (ip) => {
 345→    const normalized = ip.toLowerCase();
 346→    return (
 347→        normalized === '::1' ||
 348→        normalized.startsWith('fc') ||
 349→        normalized.startsWith('fd') ||
 350→        normalized.startsWith('fe80:')
 351→    );
 352→};
 353→
 354→const isPrivateIpAddress = (ip) => {
 355→    const ipVersion = net.isIP(ip);
 356→    if (ipVersion === 4) return isPrivateIpv4Address(ip);
 357→    if (ipVersion === 6) return isPrivateIpv6Address(ip);
 358→    return true;
 359→};
