 612→app.use((req, res, next) => {
 613→    if (req.method !== "GET") {
 614→        return next();
 615→    }
 616→
 617→    const normalizedPath = normalizeApiPath(req.path);
 618→    const isPersonalized = isPersonalizedGetRequest(req);
