 826→    const debugMode = isShareImageDebugRequest(req);
 827→
 828→    // Serve from cache if available (skip for debug)
 829→    if (!debugMode) {
 830→        const cached = getShareImageCached(`post:${journalId}`);
 831→        if (cached) {
 832→            res.set('Content-Type', 'image/jpeg');
 833→            res.set('Cache-Control', 'public, max-age=3600');
 834→            return res.send(cached);
 835→        }
 836→    }
 837→
 838→    await ensureShareFonts();
 839→    const debugPayload = {
 840→        ok: false,
 841→        fallback: false,
 842→        journalId,
 843→        stage: 'start',
 844→        reason: '',
 845→        meta: {
 846→            imageCandidateSource: null,
 847→            imageCandidateRaw: null,
 848→            imageCandidateResolved: null,
 849→            upstreamFinalUrl: null,
 850→            upstreamContentType: null,
 851→            upstreamBytes: null,
 852→            outputBytes: null,
 853→        },
 854→    };
 855→
 856→    const fallbackWithReason = (reason) => {
 857→        debugPayload.ok = false;
 858→        debugPayload.fallback = true;
 859→        debugPayload.stage = 'fallback';
 860→        debugPayload.reason = reason;
 861→        if (debugMode) {
 862→            return sendShareImageDebug(res, debugPayload);
 863→        }
 864→        return res.redirect(302, DEFAULT_OG_IMAGE_URL);
 865→    };
 866→
 867→    try {
 868→        const journal = await getShareJournal(journalId);
 869→        debugPayload.stage = 'journal_loaded';
 870→        if (!journal) {
 871→            return fallbackWithReason('journal_not_found');
 872→        }
 873→
 874→        const shareMeta = buildShareMetaFromJournal(journal);
 875→        debugPayload.stage = 'candidate_extracted';
 876→        debugPayload.meta.imageCandidateSource = shareMeta.imageCandidateSource;
 877→        debugPayload.meta.imageCandidateRaw = shareMeta.imageCandidate;
 878→
 879→        const candidateEvaluation = evaluateShareImageCandidate(shareMeta.imageCandidate);
 880→        debugPayload.meta.imageCandidateResolved = candidateEvaluation.resolvedUrl;
 881→        if (!candidateEvaluation.ok || !candidateEvaluation.resolvedUrl) {
 882→            return fallbackWithReason(candidateEvaluation.reason);
 883→        }
 884→
 885→        const normalizedFallbackUrl = new URL(DEFAULT_OG_IMAGE_URL).toString();
 886→        if (candidateEvaluation.resolvedUrl === normalizedFallbackUrl) {
 887→            return fallbackWithReason('candidate_is_default_fallback');
 888→        }
 889→
 890→        debugPayload.stage = 'fetching_upstream';
 891→        const remoteImage = await fetchRemoteImageBuffer(candidateEvaluation.resolvedUrl);
 892→        debugPayload.stage = 'upstream_loaded';
 893→        debugPayload.meta.upstreamFinalUrl = remoteImage.finalUrl;
 894→        debugPayload.meta.upstreamContentType = remoteImage.contentType;
 895→        debugPayload.meta.upstreamBytes = remoteImage.byteLength;
 896→
 897→        debugPayload.stage = 'converting_image';
 898→        const ogImageBuffer = await convertToOgJpeg(remoteImage.buffer);
 899→        debugPayload.stage = 'converted_image';
 900→        debugPayload.ok = true;
 901→        debugPayload.reason = 'ok';
 902→        debugPayload.meta.outputBytes = ogImageBuffer.length;
 903→
 904→        if (debugMode) {
 905→            return sendShareImageDebug(res, debugPayload);
 906→        }
 907→
 908→        setShareImageCached(`post:${journalId}`, ogImageBuffer);
 909→        res.set('Content-Type', 'image/jpeg');
 910→        res.set('Cache-Control', 'public, max-age=3600');
 911→        return res.send(ogImageBuffer);
 912→    } catch (err) {
 913→        debugPayload.stage = 'error';
 914→        debugPayload.reason = err?.message || 'unknown_error';
