1041→const sendMetrics = (req, res) => {
1042→    if (!isMetricsAuthorized(req)) {
1043→        return res.status(403).json({ error: 'forbidden' });
1044→    }
1045→
1046→    res.set('Cache-Control', 'no-store');
1047→    return res.status(200).json(buildMetricsPayload());
1048→};
