 1→import supabase from "../services/supabase.js";
 2→
 3→export const extractBearerToken = (authHeader = "") => {
 4→    const trimmed = typeof authHeader === "string" ? authHeader.trim() : "";
 5→    if (!trimmed) return "";
 6→
 7→    const bearerMatch = trimmed.match(/^Bearer\s+(.+)$/i);
 8→    if (bearerMatch?.[1]) {
 9→        return bearerMatch[1].trim();
10→    }
11→
12→    return trimmed;
13→};
14→
15→export const resolveAuthUser = async (token) => {
16→    if (!token) {
17→        return { user: null, error: null };
18→    }
19→
20→    const { data: authData, error: authError } = await supabase.auth.getUser(token);
21→    if (authError || !authData?.user?.id) {
22→        return { user: null, error: authError || new Error("missing user id") };
23→    }
24→
25→    return { user: authData.user, error: null };
26→};
27→
28→export const requireAuth = async (req, res, next) => {
29→    const token = extractBearerToken(req.headers?.authorization);
30→    if (!token) {
31→        return res.status(401).json({ error: 'not authorized' });
32→    }
33→
34→    const { user, error } = await resolveAuthUser(token);
35→    if (error || !user?.id) {
36→        console.error('auth middleware error:', error?.message || 'missing user id');
37→        return res.status(401).json({ error: 'not authorized' });
38→    }
39→
40→    req.userId = user.id;
41→    req.authUser = user;
42→    return next();
43→};
44→
45→export const optionalAuth = async (req, _res, next) => {
46→    const token = extractBearerToken(req.headers?.authorization);
47→    if (!token) {
48→        return next();
49→    }
50→
51→    const { user } = await resolveAuthUser(token);
52→    if (user?.id) {
53→        req.userId = user.id;
54→        req.authUser = user;
55→    }
56→
57→    return next();
58→};
