590→export const getFollowingFeedService = async(limit, userId, before) => {
591→    if (!userId) {
592→        throw { status: 401, error: 'authentication required' };
593→    }
594→    if (isNaN(limit) || limit > 20 || limit < 1) {
595→        throw { status: 400, error: 'limit should be integer, not below 1 and higher than 20' };
596→    }
597→
598→    const parsedLimit = parseInt(limit);
599→
600→    // Step 1: Fetch journals via RPC (subquery stays inside Postgres — scales to 100k+ followings)
601→    const { data: rpcData, error } = await supabase.rpc('get_following_feed', {
