642→        supabase.from('bookmarks').select('journal_id').in('journal_id', journalIds).eq('user_id', userId),
643→        supabase.from('reactions').select('journal_id, reaction_type').in('journal_id', journalIds).eq('user_id', userId)
644→    ]);
645→
646→    const userHasLikedSet = new Set(userLikes.data?.map(j => j.journal_id) || []);
647→    const userHasBookmarkedSet = new Set(userBookmarks.data?.map(j => j.journal_id) || []);
648→    const userReactionMap = new Map((userReactions.data || []).map(r => [r.journal_id, r.reaction_type]));
649→
650→    await attachRepostSources(data);
651→
652→    const formattedData = data.map(journal => ({
653→        ...journal,
654→        has_liked: userHasLikedSet.has(journal.id),
655→        has_bookmarked: userHasBookmarkedSet.has(journal.id),
656→        user_reaction: userReactionMap.get(journal.id) || null
657→    }));
658→    const optimizedData = decorateJournalCollection(formattedData, JOURNAL_MEDIA_USAGE.feed);
659→
660→    const hasMore = data.length > parsedLimit;
661→    const slicedData = hasMore ? optimizedData.slice(0, parsedLimit) : optimizedData;
662→
663→    return { data: slicedData, hasMore };
664→}
