/**
 * Wraps an async controller handler to catch errors and return consistent
 * JSON error responses. Eliminates try/catch boilerplate.
 *
 * @param {Function} fn - async (req, res) => any
 * @returns {Function} Express middleware
 */
export const asyncHandler = (fn) => async (req, res, next) => {
    try {
        await fn(req, res, next);
    } catch (error) {
        console.error(error);
        const status = error?.status || 500;
        const message = error?.error || error?.message || 'internal server error';
        return res.status(status).json({ error: message });
    }
};
```

