    const headers = {};
    if (contentType) headers['Content-Type'] = contentType;
    if (token) headers['Authorization'] = `Bearer ${token}`;
    return headers;
};

/**
 * Execute an API request, parse JSON, throw on error.
 * @param {string} url
 * @param {object} options - fetch options
 * @param {string} fallbackError - error message if response has no body
 */
export const jsonRequest = async (url, options = {}, fallbackError = 'request failed') => {
    const response = await apiRequest(url, options);
    if (!response.ok) {
        const error = await response.json().catch(() => ({}));
        throw new Error(error?.error || error?.message || fallbackError);
    }
    return response.json();
};

/**
 * Authenticated JSON POST/PATCH/DELETE.
 */
export const authedJsonRequest = async (token, method, path, body, fallbackError) => {
    return jsonRequest(`${BASE_URL}${path}`, {
        method,
        headers: authHeaders(token, 'application/json'),
        body: JSON.stringify(body),
    }, fallbackError);
};

/**
 * Authenticated FormData POST (no Content-Type -- browser sets boundary).
 */
export const authedFormRequest = async (token, method, path, formData, fallbackError) => {
    return jsonRequest(`${BASE_URL}${path}`, {
        method,
        headers: authHeaders(token),
        body: formData,
    }, fallbackError);
};

/**
 * Public (no auth) GET.
 */
export const publicGet = async (path, fallbackError) => {
    return jsonRequest(`${BASE_URL}${path}`, { method: 'GET' }, fallbackError);
};

/**
 * Authenticated GET.
 */
export const authedGet = async (token, path, fallbackError) => {
    return jsonRequest(`${BASE_URL}${path}`, {
        method: 'GET',
        headers: authHeaders(token),
    }, fallbackError);
};
```

